module shift_register_4bit (clk, reset, load, data_in, data_out);
   input clk, reset, load;
   input [3:0] data_in;
   output data_out;

   reg [3:0] flip_flop;
   reg data_out;

always @(posedge clk or posedge reset) begin
    if (reset) 
    begin
        flip_flop <= 4'b0000;
        data_out <= 0;
    end 
    else 
    begin
        if (load) 
            flip_flop <= data_in;
        else 
        begin
            data_out <= flip_flop[3];
            flip_flop <= {flip_flop[2:0], 1'b0};
        end
    end
end

endmodule
